# WebFRIENDS - Auto-servido
# Guardar como WebFRIENDS.ps1, ejecutar con: click derecho > Ejecutar con PowerShell

$html = [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$l = [System.Net.HttpListener]::new()
$l.Prefixes.Add('http://localhost:8080/')
$l.Start()
Start-Process 'http://localhost:8080'
while($l.IsListening){
  $c = $l.GetContext()
  $c.Response.ContentType = 'text/html; charset=utf-8'
  $bytes = [System.Text.Encoding]::UTF8.GetBytes($html)
  $c.Response.OutputStream.Write($bytes, 0, $bytes.Length)
  $c.Response.Close()
}
